import{c as t,Q as d,j as o,m as a}from"./chunks/framework.BPKcPtvA.js";const u=JSON.parse('{"title":"Configuration","description":"","frontmatter":{},"headers":[],"relativePath":"configuration.md","filePath":"configuration.md","lastUpdated":1782764690000}'),r={name:"configuration.md"};function s(n,e,i,c,l,h){return d(),o("div",null,[...e[0]||(e[0]=[a(`<h1 id="configuration" tabindex="-1">Configuration <a class="header-anchor" href="#configuration" aria-label="Permalink to &quot;Configuration&quot;">​</a></h1><p>Ember reads configuration from environment variables at startup. A handful of settings can also be changed at runtime via the admin UI and persist in the <code>app_settings</code> table.</p><h2 id="required-env-vars" tabindex="-1">Required env vars <a class="header-anchor" href="#required-env-vars" aria-label="Permalink to &quot;Required env vars&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Var</th><th>Description</th></tr></thead><tbody><tr><td><code>EMBER_SESSION_KEY</code></td><td>securecookie key, 32+ random bytes. Generate via <code>openssl rand -base64 48</code>. Also seeds (domain-separated) the HMAC key that signs image-proxy URLs.</td></tr><tr><td><code>EMBER_ADMIN_PASSWORD</code></td><td>First-run admin password. Used only when the <code>users</code> table is empty; change via Settings → Profile after first login. <strong>Must be at least 8 characters</strong> — a shorter or empty value makes the container <strong>exit on startup</strong> with <code>bootstrap admin: …must be at least 8 characters</code> rather than starting with no usable account.</td></tr></tbody></table><h2 id="optional-env-vars" tabindex="-1">Optional env vars <a class="header-anchor" href="#optional-env-vars" aria-label="Permalink to &quot;Optional env vars&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Var</th><th>Default</th><th>Notes</th></tr></thead><tbody><tr><td><code>EMBER_ADDR</code></td><td><code>:8080</code></td><td>Bind address.</td></tr><tr><td><code>EMBER_DB_PATH</code></td><td><code>/data/ember.db</code></td><td>SQLite file path.</td></tr><tr><td><code>EMBER_ADMIN_USER</code></td><td><code>admin</code></td><td>First-run admin username.</td></tr><tr><td><code>EMBER_OLLAMA_URL</code></td><td><code>http://ollama:11434</code></td><td>Ollama API endpoint.</td></tr><tr><td><code>EMBER_OLLAMA_MODEL</code></td><td><code>qwen2.5:0.5b</code></td><td>Initial active model. The admin UI can swap to any pulled model live.</td></tr><tr><td><code>EMBER_DISABLE_SUMMARIES</code></td><td><code>0</code></td><td>Skip LLM summarization entirely. Articles still surface (poller stamps <code>summary_model=&#39;disabled&#39;</code>).</td></tr><tr><td><code>EMBER_DISABLE_IMAGES</code></td><td><code>0</code></td><td>Drop article hero images at ingest.</td></tr><tr><td><code>EMBER_ALLOW_PRIVATE_URLS</code></td><td><code>0</code></td><td>Bypass the SSRF private-IP block so feeds on RFC1918 / loopback addresses can be subscribed. The scheme allowlist and the non-web service-port block still apply. <strong>Only set this if you trust every user who can add feeds.</strong></td></tr><tr><td><code>EMBER_PUBLIC_URL</code></td><td>—</td><td>Canonical <code>scheme://host</code> users hit, e.g. <code>https://reader.example.com</code>. Required to enable passkey / WebAuthn sign-in.</td></tr><tr><td><code>EMBER_SECURE_COOKIES</code></td><td><code>1</code></td><td><code>Secure</code> flag on the session + CSRF cookies. Ember serves plain HTTP and expects a TLS-terminating proxy in front, so leave this on. Set <code>0</code> <strong>only</strong> for a deliberate plain-HTTP deployment (e.g. private VPN) — otherwise browsers drop the cookies over HTTP and login silently fails.</td></tr><tr><td><code>EMBER_TRUSTED_PROXIES</code></td><td>—</td><td>Comma/space-separated CIDRs or IPs of the proxy in front of Ember. <code>X-Real-IP</code> (rate-limit keying) and <code>X-Forwarded-Proto</code> (HTTPS detection for HSTS) are honored <strong>only</strong> from these peers. Empty = trust nobody (Ember is the edge; reads the real client from the connection). The bundled compose sets this to the Caddy bridge range.</td></tr><tr><td><code>EMBER_SMTP_HOST</code></td><td>—</td><td>SMTP server hostname. Required to enable the daily-digest email feature. Can also be set per-server in <strong>Settings → Email / SMTP</strong> (admin), which takes precedence.</td></tr><tr><td><code>EMBER_SMTP_PORT</code></td><td><code>587</code></td><td>SMTP port. Overrideable in <strong>Settings → Email / SMTP</strong>.</td></tr><tr><td><code>EMBER_SMTP_USER</code></td><td>—</td><td>SMTP auth username (optional; omit for relays without auth). Overrideable in <strong>Settings → Email / SMTP</strong>.</td></tr><tr><td><code>EMBER_SMTP_PASSWORD</code></td><td>—</td><td>SMTP auth password. Overrideable in <strong>Settings → Email / SMTP</strong> (stored write-only — never echoed back to the UI).</td></tr><tr><td><code>EMBER_SMTP_FROM</code></td><td>—</td><td><code>From:</code> address used on digest emails. Overrideable in <strong>Settings → Email / SMTP</strong>.</td></tr><tr><td><code>EMBER_SMTP_STARTTLS</code></td><td><code>1</code></td><td>STARTTLS on submission ports (587). When on, the server <strong>must</strong> offer STARTTLS or the send fails (no silent plaintext downgrade). Set <code>0</code> only for a <strong>loopback</strong> relay (<code>localhost</code> / <code>127.0.0.1</code> / <code>::1</code>) — plain SMTP to any remote host is refused so credentials never cross the network in the clear. Overrideable in <strong>Settings → Email / SMTP</strong>.</td></tr><tr><td><code>EMBER_FRESH_WINDOW</code></td><td><code>6h</code></td><td>How recent an article must be to appear in the &quot;Fresh&quot; smart view. Fresh lists recent <strong>unread</strong> articles, matching its sidebar badge.</td></tr><tr><td><code>EMBER_POLL_CONCURRENCY</code></td><td><code>8</code></td><td>Number of feed-fetch worker goroutines.</td></tr><tr><td><code>EMBER_POLL_TICK</code></td><td><code>60s</code></td><td>How often the poller scans for feeds due to fetch.</td></tr><tr><td><code>EMBER_POLL_MIN_INTERVAL</code></td><td><code>30m</code></td><td>Floor for the adaptive per-feed fetch interval (&quot;check feeds every…&quot;). Active feeds settle near this value; quiet feeds back off up to 6h. Range-validated <strong>5m–24h</strong>. Admins can change it at runtime in <strong>Settings → (Email/Data) → Feed check interval</strong> (persisted in <code>app_settings</code>, overrides this env default, no restart needed).</td></tr><tr><td><code>EMBER_SESSION_TTL</code></td><td><code>24h</code></td><td>Lifetime of a freshly-issued session cookie. Go duration (e.g. <code>30m</code>, <code>12h</code>, <code>168h</code>). Range-validated (5m–90d). Admin UI override in <strong>Settings → Sessions</strong> takes precedence when set.</td></tr><tr><td><code>EMBER_LOG_LEVEL</code></td><td><code>info</code></td><td><code>debug</code> / <code>info</code> / <code>warn</code> / <code>error</code>.</td></tr><tr><td><code>EMBER_TEST_MODE</code></td><td><code>0</code></td><td>Seeds fake admin + articles; loosens cookie Secure flag; and (when <code>EMBER_SESSION_KEY</code> is unset) falls back to a <strong>hardcoded, publicly-known session signing key</strong> — session cookies become forgeable. Logs a loud warning at startup. <strong>Never enable in production.</strong></td></tr><tr><td><code>EMBER_HSTS_PRELOAD</code></td><td><code>0</code></td><td>Appends <code>; preload</code> to the <code>Strict-Transport-Security</code> header. Long-term, browser-level commitment — only set after the domain is (or will be) submitted to the <a href="https://hstspreload.org" target="_blank" rel="noreferrer">HSTS preload list</a>.</td></tr><tr><td><code>EMBER_EMAIL_DOMAIN</code></td><td>—</td><td>Enables the per-user newsletter inbox. Without it, the SMTP listener doesn&#39;t start and the inbox endpoints return <code>enabled: false</code>. See <a href="/email-inbox">Email newsletter inbox</a> for the operator setup.</td></tr><tr><td><code>EMBER_EMAIL_LISTEN_ADDR</code></td><td><code>:2525</code></td><td>Inbound SMTP bind address for the newsletter inbox. Front with Caddy layer4 / haproxy / nginx stream to publish on port 25.</td></tr><tr><td><code>EMBER_EMAIL_MAX_BYTES</code></td><td><code>26214400</code> (25 MiB)</td><td>Per-message size cap on inbound newsletter mail.</td></tr></tbody></table><h2 id="runtime-settings-persist-across-restarts" tabindex="-1">Runtime settings (persist across restarts) <a class="header-anchor" href="#runtime-settings-persist-across-restarts" aria-label="Permalink to &quot;Runtime settings (persist across restarts)&quot;">​</a></h2><p>Stored in the <code>app_settings</code> KV. Edit via the admin UI in <strong>Settings → ...</strong>.</p><table tabindex="0"><thead><tr><th>Setting</th><th>Where to change</th></tr></thead><tbody><tr><td>Active LLM model</td><td>Language model</td></tr><tr><td>Temperature / Top P / Context window</td><td>Language model → Tuning</td></tr><tr><td>Session cookie TTL (overrides <code>EMBER_SESSION_TTL</code>)</td><td>Sessions</td></tr><tr><td>App name, page title, favicon URL</td><td>Branding</td></tr><tr><td>Backup schedule + retention (<code>db_backup_keep</code>, default 7)</td><td>Database</td></tr><tr><td>Backup directory (<code>db_backup_dir</code>, default <code>/data/backups</code>)</td><td>Database → Backups → Directory (<a href="#custom-backup-directory">setup</a>)</td></tr><tr><td>Cleanup schedule + window (<code>db_cleanup_older_days</code>, default 90)</td><td>Database</td></tr><tr><td>OPML export directory + schedule + retention (<code>opml_export_dir</code> default <code>/data/exports</code>, <code>opml_keep</code> default 12)</td><td>Database → OPML export (<a href="#custom-backup-directory">setup</a>)</td></tr><tr><td>SMTP host / port / username / password / from / STARTTLS</td><td>Email / SMTP</td></tr><tr><td>Initial feed-backlog window (default <strong>24 hours</strong>; 0 = no gate)</td><td>Email / SMTP → Initial backlog window</td></tr><tr><td>Reading window (default 24h; range 24–168h)</td><td>Feeds → Reading window</td></tr><tr><td>Search window (default 48h; range 24–168h)</td><td>Feeds → Search window</td></tr></tbody></table><h3 id="custom-backup-directory" tabindex="-1">Custom backup directory <a class="header-anchor" href="#custom-backup-directory" aria-label="Permalink to &quot;Custom backup directory&quot;">​</a></h3><p>Database backups — the manual <strong>Back up now</strong> button and the scheduled job — are written to <code>/data/backups</code> by default, inside the container&#39;s <code>/data</code> volume. To put them on a host path you control (a specific disk, a NAS mount, a directory you already back up off-box), change the path <strong>and</strong> bind-mount it:</p><ol><li><p><strong>Bind-mount a host directory</strong> into the ember service in <code>deploy/docker-compose.yml</code>. Alongside the existing <code>ember-data:/data</code> volume, add a bind mount — <code>host path : container path</code>:</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">services</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  ember</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    volumes</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">      - </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">ember-data:/data</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">      - </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/srv/ember/backups:/backups</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # ← your host path : container path</span></span></code></pre></div><p>The host directory must be <strong>writable by the container&#39;s user</strong>. Ember&#39;s image runs as the distroless <code>nonroot</code> user (UID <strong>65532</strong>), and a bind mount keeps the host&#39;s ownership — unlike the <code>/data</code> named volume, which is set up for you. Create the directory and hand it to that user before starting:</p><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mkdir</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /srv/ember/backups</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> chown</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -R</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 65532:65532</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /srv/ember/backups</span></span></code></pre></div><p>Use <code>-R</code> so any snapshots already in the directory (e.g. created by an earlier run under a different user) are re-owned too. This matters for <strong>deleting</strong> as well as creating: removing a file needs the <em>directory</em> writable by UID 65532. Without the right ownership, &quot;Back up now&quot; fails with <code>… is not writable by the server (running as uid 65532)</code>, and the per-file <strong>Delete</strong> button reports <em>&quot;the backup directory isn&#39;t writable by the server …&quot;</em>.</p><div class="warning custom-block"><p class="custom-block-title">Docker Desktop / WSL2</p><p>A bind mount pointing at a <strong>Windows</strong> path (<code>/mnt/c/…</code>, <code>C:\\…</code>) ignores <code>chown</code> — ownership is synthesized by the filesystem driver, so the container user can never be made the owner. Use a directory on the Linux filesystem, or keep backups on the <code>/data</code> named volume, if you want to manage them from the UI.</p></div></li><li><p><strong>Point Ember at it.</strong> In <strong>Settings → Database → Backups → Directory</strong>, enter the container-side path (<code>/backups</code> in the example), then <strong>Save schedule</strong>. It must be an absolute path the container can write to. Leave it empty to reset to <code>/data/backups</code>.</p></li></ol><div class="warning custom-block"><p class="custom-block-title">Bind-mount it first</p><p>The directory only persists on the host if you&#39;ve bind-mounted it. Ember can&#39;t create the host mount for you — add it to the compose file and recreate the container <strong>before</strong> entering the container path in the UI. A path that isn&#39;t backed by a mount is lost when the container is recreated.</p></div><p>The same directory is used by both the scheduled job and the manual button; <strong>Keep</strong> prunes the oldest snapshots beyond the count you set.</p><p>The <strong>OPML export directory</strong> (<strong>Settings → Database → OPML export → Directory</strong>, default <code>/data/exports</code>) works exactly the same way — bind-mount the host path, <code>chown -R</code> it to UID 65532 (same ownership caveat for creating <em>and</em> deleting exports, and the same Windows-path limitation), then enter the container path. Its <strong>Keep</strong> prunes old exports the same way.</p><h3 id="time-windows-retention-and-counts" tabindex="-1">Time windows, retention, and counts <a class="header-anchor" href="#time-windows-retention-and-counts" aria-label="Permalink to &quot;Time windows, retention, and counts&quot;">​</a></h3><p>Ember keeps articles for a <strong>fixed rolling 1-week (168h) retention window</strong>, then prunes them automatically (a daily delete-only sweep). Starred, Read-Later, board-pinned, and shared articles are exempt and kept indefinitely. This retention window is <strong>not</strong> configurable — it&#39;s the hard ceiling for the two settings below, because you can&#39;t surface what&#39;s already been pruned.</p><ul><li><strong>Ingest</strong> — a brand-new feed pulls only the last 24h on its first fetch (the <em>initial backlog window</em>). Existing feeds only add genuinely new items (GUID + content-hash dedup), so reposts don&#39;t reappear.</li><li><strong>Reading window</strong> (default 24h, extendable to 168h) — the <em>floor</em> for how far back the unread views and counts reach. <em>Today</em> always shows exactly this window, newest first. A feed, a category, and <em>All Unread</em> show at least this window but <strong>extend back to your previous login</strong> when you&#39;ve been away longer (so time away surfaces everything new since), clamped at the retention window. Older articles stay in the database (searchable) but are hidden from these views. Because a feed/category list and its sidebar badge share this one cutoff, the badge counts exactly the set the column pages through — the list loads 50 at a time with a <strong>Load more</strong> button (search loads 25 at a time), so the badge is the running total and &quot;Load more&quot; reveals the rest.</li><li><strong>Search window</strong> (default 48h, extendable to 168h) — full-text search matches articles published within this window. Results older than 24h are tagged with a date pill showing when they were polled. The window can&#39;t exceed retention — that&#39;s the safeguard.</li></ul><p>Sidebar badges (All Unread, per-folder, per-feed) are computed server-side with the <strong>same</strong> window, summary gate, and cross-feed dedup as the article list, so a badge always matches the column it summarizes. When AI summarization is enabled, articles are hidden from every view and count until the summarizer has processed them; when it&#39;s disabled, nothing is gated.</p><p>Each user also has client-side preferences stored in browser <code>localStorage</code>:</p><table tabindex="0"><thead><tr><th>Preference</th><th>Default</th><th>Key</th></tr></thead><tbody><tr><td>Theme</td><td>Auto (OS)</td><td><code>ember:theme</code></td></tr><tr><td>Article density</td><td>Cards</td><td><code>ember:density</code></td></tr><tr><td>Sidebar collapsed</td><td>Open</td><td><code>ember:sidebar</code></td></tr><tr><td>AI summary card visible</td><td>On</td><td><code>ember:show-summary</code></td></tr><tr><td>Summary card collapsed</td><td>Open</td><td><code>ember:summary-collapsed</code></td></tr><tr><td>Custom theme palette</td><td>n/a</td><td><code>ember:custom</code></td></tr></tbody></table><h2 id="hardware-aware-model-recommendation" tabindex="-1">Hardware-aware model recommendation <a class="header-anchor" href="#hardware-aware-model-recommendation" aria-label="Permalink to &quot;Hardware-aware model recommendation&quot;">​</a></h2><p>Run <code>ember probe</code> (or open the admin Language model page) to see a recommendation based on detected RAM, CPU count, and GPU.</p><table tabindex="0"><thead><tr><th>RAM</th><th>GPU</th><th>Recommended</th></tr></thead><tbody><tr><td>&lt; 2 GiB</td><td>—</td><td>Disable summaries</td></tr><tr><td>2–4 GiB</td><td>—</td><td><code>qwen2.5:0.5b</code></td></tr><tr><td>4–8 GiB</td><td>—</td><td><code>qwen2.5:0.5b</code></td></tr><tr><td>8–16 GiB</td><td>—</td><td><code>qwen2.5:1.5b</code></td></tr><tr><td>16 GiB+</td><td>—</td><td><code>qwen2.5:3b</code></td></tr><tr><td>any</td><td>NVIDIA / Apple Silicon</td><td><code>qwen2.5:7b</code></td></tr></tbody></table><h2 id="stack-level-env-vars-docker-compose" tabindex="-1">Stack-level env vars (docker-compose) <a class="header-anchor" href="#stack-level-env-vars-docker-compose" aria-label="Permalink to &quot;Stack-level env vars (docker-compose)&quot;">​</a></h2><p>These configure the bundled <code>deploy/docker-compose.yml</code> stack rather than the Ember binary itself.</p><table tabindex="0"><thead><tr><th>Var</th><th>Default</th><th>Notes</th></tr></thead><tbody><tr><td><code>EMBER_HOSTNAME</code></td><td><code>localhost</code></td><td>Hostname Caddy serves. Real DNS name → automatic Let&#39;s Encrypt.</td></tr><tr><td><code>CADDY_EMAIL</code></td><td><code>admin@localhost</code></td><td>Email registered with Let&#39;s Encrypt for ACME notifications. Set this when using a real hostname.</td></tr><tr><td><code>EMBER_HTTP_PORT</code></td><td><code>80</code></td><td>Host port Caddy publishes for HTTP. Change when 80 is taken locally.</td></tr><tr><td><code>EMBER_HTTPS_PORT</code></td><td><code>443</code></td><td>Host port Caddy publishes for HTTPS. Change when 443 is taken locally.</td></tr><tr><td><code>EMBER_DISABLE_HTTPS_REDIRECT</code></td><td><em>(unset)</em></td><td>Set to <code>1</code> to turn off Caddy&#39;s default 80 → 443 redirect. Use when an upstream proxy already terminates TLS.</td></tr></tbody></table><p>If you change the ports, reach the site at the mapped port — e.g. <code>EMBER_HTTPS_PORT=8443</code> → visit <code>https://localhost:8443</code>. Inside the container Caddy still listens on 80/443; only the host-side mapping changes.</p><h3 id="let-s-encrypt" tabindex="-1">Let&#39;s Encrypt <a class="header-anchor" href="#let-s-encrypt" aria-label="Permalink to &quot;Let&#39;s Encrypt&quot;">​</a></h3><p>Caddy fetches a free Let&#39;s Encrypt cert automatically when <strong>all three</strong> of these are true:</p><ol><li><code>EMBER_HOSTNAME</code> is a real DNS name that resolves to this server (e.g. <code>ember.example.com</code>).</li><li><code>CADDY_EMAIL</code> is a valid email address.</li><li>The public internet can reach port <code>80</code> (HTTP-01 challenge) or port <code>443</code> (TLS-ALPN-01 challenge) on this host.</li></ol><p>If you remap <code>EMBER_HTTP_PORT</code> / <code>EMBER_HTTPS_PORT</code> <em>and</em> expect Let&#39;s Encrypt to issue certs, ensure your public ingress (router / upstream proxy / Cloudflare) still terminates on 80/443 and forwards to your mapped host ports. For homelab use with <code>tls internal</code> in the Caddyfile, any ports work fine.</p><h3 id="http-→-https-redirect" tabindex="-1">HTTP → HTTPS redirect <a class="header-anchor" href="#http-→-https-redirect" aria-label="Permalink to &quot;HTTP → HTTPS redirect&quot;">​</a></h3><p>Caddy redirects port 80 to 443 by default for any site with managed TLS. Set <code>EMBER_DISABLE_HTTPS_REDIRECT=1</code> in <code>.env</code> to turn this off — needed when Ember sits behind another reverse proxy (Traefik, nginx, Cloudflare Tunnel, etc.) that already handles the redirect or terminates TLS upstream.</p><h2 id="reverse-proxy" tabindex="-1">Reverse proxy <a class="header-anchor" href="#reverse-proxy" aria-label="Permalink to &quot;Reverse proxy&quot;">​</a></h2><p>Ember expects TLS to be terminated upstream. The reference <code>Caddyfile</code> in <code>deploy/Caddyfile</code> covers:</p><ul><li>Automatic Let&#39;s Encrypt for a real hostname (default).</li><li><code>tls internal</code> for self-signed homelab certs.</li><li><code>EMBER_DISABLE_HTTPS_REDIRECT</code> toggle for the 80 → 443 redirect.</li><li>Forwarding <code>X-Real-IP</code> + <code>X-Forwarded-Proto</code> (Ember honors these <strong>only</strong> from peers listed in <code>EMBER_TRUSTED_PROXIES</code>; the bundled compose sets it to the Caddy bridge range). Without it, Ember treats itself as the edge and ignores both headers.</li></ul><p>If you front Ember with Cloudflare, set the <a href="https://developers.cloudflare.com/ssl/origin-configuration/authenticated-origin-pull/" target="_blank" rel="noreferrer">authenticated origin pull</a> so only Cloudflare can reach your origin.</p>`,38)])])}const m=t(r,[["render",s]]);export{u as __pageData,m as default};
